                           '2022-03', '2022-04', '2022-05']

            has_date = False
            for pattern in date_patterns:
                if pattern in line or (i+1 < len(lines) and pattern in lines[i+1]):
                    has_date = True
                    break

            if has_date:
                # Find project name (look backwards up to 5 lines)
                project_name = None
                for j in range(i-1, max(-1, i-6), -1):
